using ContosoUniversity.Data;
using Microsoft.EntityFrameworkCore;
using ContosoUniversity.Models;
using System;
using System.Collections.Generic;

namespace ContosoUniversity.Tests
{
    /// <summary>
    /// Provides a fresh in-memory SchoolContext for each test.
    /// </summary>
    public static class TestDbContextFactory
    {
        public static SchoolContext Create(string dbName = null)
        {
            dbName ??= Guid.NewGuid().ToString();
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(databaseName: dbName)
                .Options;

            var context = new SchoolContext(options);
            context.Database.EnsureCreated();
            return context;
        }

        public static SchoolContext CreateWithStudents(string dbName = null)
        {
            var context = Create(dbName);
            context.Students.AddRange(
                new Student { ID = 1, LastName = "Alexander", FirstMidName = "Carson", EnrollmentDate = new DateTime(2020, 9, 1) },
                new Student { ID = 2, LastName = "Alonso", FirstMidName = "Meredith", EnrollmentDate = new DateTime(2021, 9, 1) },
                new Student { ID = 3, LastName = "Barzdukas", FirstMidName = "Gytis", EnrollmentDate = new DateTime(2020, 9, 1) }
            );
            context.SaveChanges();
            return context;
        }

        public static SchoolContext CreateWithCoursesAndDepartments(string dbName = null)
        {
            var context = Create(dbName);

            var instructor = new Instructor
            {
                ID = 1,
                LastName = "Fakhouri",
                FirstMidName = "Fadi",
                HireDate = new DateTime(2002, 7, 6),
                CourseAssignments = new List<CourseAssignment>()
            };
            context.Instructors.Add(instructor);

            var department = new Department
            {
                DepartmentID = 1,
                Name = "Engineering",
                Budget = 350000m,
                StartDate = new DateTime(2007, 9, 1),
                InstructorID = 1
            };
            context.Departments.Add(department);

            context.Courses.AddRange(
                new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = 1 },
                new Course { CourseID = 4022, Title = "Microeconomics", Credits = 3, DepartmentID = 1 },
                new Course { CourseID = 1045, Title = "Calculus", Credits = 4, DepartmentID = 1 }
            );

            context.SaveChanges();
            return context;
        }

        public static SchoolContext CreateWithInstructors(string dbName = null)
        {
            var context = Create(dbName);

            var dept = new Department
            {
                DepartmentID = 1,
                Name = "Engineering",
                Budget = 350000m,
                StartDate = new DateTime(2007, 9, 1)
            };
            context.Departments.Add(dept);

            context.Courses.Add(new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = 1 });

            context.Instructors.AddRange(
                new Instructor
                {
                    ID = 1,
                    LastName = "Fakhouri",
                    FirstMidName = "Fadi",
                    HireDate = new DateTime(2002, 7, 6),
                    CourseAssignments = new List<CourseAssignment>
                    {
                        new CourseAssignment { CourseID = 1050, InstructorID = 1 }
                    },
                    OfficeAssignment = new OfficeAssignment { InstructorID = 1, Location = "Smith 17" }
                },
                new Instructor
                {
                    ID = 2,
                    LastName = "Harui",
                    FirstMidName = "Roger",
                    HireDate = new DateTime(1998, 7, 1),
                    CourseAssignments = new List<CourseAssignment>()
                }
            );
            context.SaveChanges();
            return context;
        }
    }
}

