using Xunit;
using ContosoUniversity.Services;
using ContosoUniversity.Models;

namespace ContosoUniversity.Tests.Services
{
    public class NotificationServiceTests
    {
        [Fact]
        public void SendNotification_WithDisplayName_EnqueuesNotification()
        {
            // Arrange
            var service = new NotificationService();

            // Act
            service.SendNotification("Student", "1", "Carson Alexander", EntityOperation.CREATE, "Admin");

            // Assert
            var notification = service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("Student", notification.EntityType);
            Assert.Equal("1", notification.EntityId);
            Assert.Equal("CREATE", notification.Operation);
            Assert.Contains("Carson Alexander", notification.Message);
            Assert.Contains("created", notification.Message);
            Assert.Equal("Admin", notification.CreatedBy);
            Assert.False(notification.IsRead);
        }

        [Fact]
        public void SendNotification_WithoutDisplayName_UsesEntityIdInMessage()
        {
            var service = new NotificationService();

            service.SendNotification("Course", "42", EntityOperation.UPDATE, "Teacher");

            var notification = service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Contains("ID: 42", notification.Message);
            Assert.Contains("updated", notification.Message);
        }

        [Fact]
        public void SendNotification_DeleteOperation_GeneratesDeleteMessage()
        {
            var service = new NotificationService();

            service.SendNotification("Department", "5", "Engineering", EntityOperation.DELETE, "Admin");

            var notification = service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Contains("deleted", notification.Message);
            Assert.Contains("Engineering", notification.Message);
        }

        [Fact]
        public void SendNotification_NullUserName_DefaultsToSystem()
        {
            var service = new NotificationService();

            service.SendNotification("Student", "1", "Test", EntityOperation.CREATE, null);

            var notification = service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("System", notification.CreatedBy);
        }

        [Fact]
        public void ReceiveNotification_EmptyQueue_ReturnsNull()
        {
            var service = new NotificationService();

            // Drain whatever might be left from other tests (static queue)
            while (service.ReceiveNotification() != null) { }

            var result = service.ReceiveNotification();
            Assert.Null(result);
        }

        [Fact]
        public void SendNotification_MultipleMessages_ReceivesInOrder()
        {
            var service = new NotificationService();
            // Drain queue first
            while (service.ReceiveNotification() != null) { }

            service.SendNotification("A", "1", "First", EntityOperation.CREATE);
            service.SendNotification("B", "2", "Second", EntityOperation.UPDATE);

            var first = service.ReceiveNotification();
            var second = service.ReceiveNotification();

            Assert.Equal("A", first.EntityType);
            Assert.Equal("B", second.EntityType);
        }

        [Fact]
        public void MarkAsRead_DoesNotThrow()
        {
            var service = new NotificationService();

            // MarkAsRead is a no-op in this implementation but should not throw
            var ex = Record.Exception(() => service.MarkAsRead(999));
            Assert.Null(ex);
        }

        [Fact]
        public void Dispose_DoesNotThrow()
        {
            var service = new NotificationService();
            var ex = Record.Exception(() => service.Dispose());
            Assert.Null(ex);
        }
    }
}

