using System;
using System.Linq;
using Microsoft.AspNetCore.Mvc;
using Xunit;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;

namespace ContosoUniversity.Tests.Controllers
{
    public class StudentsControllerTests
    {
        private SchoolContext CreateContext() => TestDbContextFactory.CreateWithStudents();

        [Fact]
        public void Index_NoParameters_ReturnsViewWithAllStudents()
        {
            using var context = CreateContext();
            var controller = new StudentsController(context);

            var result = controller.Index(null, null, null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal(3, model.Count);
        }

        [Fact]
        public void Index_SearchString_FiltersStudentsByLastName()
        {
            using var context = CreateContext();
            var controller = new StudentsController(context);

            var result = controller.Index(null, null, "Alexander", null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Single(model);
            Assert.Equal("Alexander", model[0].LastName);
        }

        [Fact]
        public void Index_SearchString_FiltersStudentsByFirstName()
        {
            using var context = CreateContext();
            var controller = new StudentsController(context);

            var result = controller.Index(null, null, "Meredith", null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Single(model);
            Assert.Equal("Alonso", model[0].LastName);
        }

        [Fact]
        public void Index_SortByNameDescending_ReturnsSortedStudents()
        {
            using var context = CreateContext();
            var controller = new StudentsController(context);

            var result = controller.Index("name_desc", null, null, null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal("Barzdukas", model[0].LastName);
        }

        [Fact]
        public void Index_SortByDate_ReturnsSortedByEnrollmentDateAscending()
        {
            using var context = CreateContext();
            var controller = new StudentsController(context);

            var result = controller.Index("Date", null, null, null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            // 2020 students come first
            Assert.Equal(new DateTime(2020, 9, 1), model[0].EnrollmentDate);
        }

        [Fact]
        public void Index_SortByDateDescending_ReturnsSortedByEnrollmentDateDescending()
        {
            using var context = CreateContext();
            var controller = new StudentsController(context);

            var result = controller.Index("date_desc", null, null, null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal(new DateTime(2021, 9, 1), model[0].EnrollmentDate);
        }

        [Fact]
        public void Index_SearchStringProvided_ResetsPageTo1()
        {
            using var context = CreateContext();
            var controller = new StudentsController(context);

            var result = controller.Index(null, null, "A", null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal(1, model.PageIndex);
        }

        [Fact]
        public void Index_CurrentFilter_UsedWhenSearchStringIsNull()
        {
            using var context = CreateContext();
            var controller = new StudentsController(context);

            var result = controller.Index(null, "Alexander", null, null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Single(model);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithStudent()
        {
            using var context = CreateContext();
            // Add enrollments for the student
            context.Courses.Add(new Course { CourseID = 100, Title = "Test Course", Credits = 3, DepartmentID = 0 });
            context.Enrollments.Add(new Enrollment { EnrollmentID = 1, CourseID = 100, StudentID = 1 });
            context.SaveChanges();

            var controller = new StudentsController(context);

            var result = controller.Details(1) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Student>(result.Model);
            Assert.Equal("Alexander", model.LastName);
        }

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            using var context = CreateContext();
            var controller = new StudentsController(context);

            var result = controller.Details(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void Create_Get_ReturnsViewWithDefaultDate()
        {
            using var context = CreateContext();
            var controller = new StudentsController(context);

            var result = controller.Create() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Student>(result.Model);
            Assert.Equal(DateTime.Today, model.EnrollmentDate);
        }

        [Fact]
        public void Create_Post_ValidStudent_RedirectsToIndex()
        {
            using var context = CreateContext();
            var controller = new StudentsController(context);
            var student = new Student
            {
                LastName = "NewStudent",
                FirstMidName = "Test",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            var result = controller.Create(student) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Equal(4, context.Students.Count());
        }

        [Fact]
        public void Create_Post_InvalidEnrollmentDate_ReturnsViewWithError()
        {
            using var context = CreateContext();
            var controller = new StudentsController(context);
            var student = new Student
            {
                LastName = "NewStudent",
                FirstMidName = "Test",
                EnrollmentDate = DateTime.MinValue
            };

            var result = controller.Create(student) as ViewResult;

            Assert.NotNull(result);
            Assert.False(controller.ModelState.IsValid);
        }

        [Fact]
        public void Create_Post_DateOutOfRange_ReturnsViewWithError()
        {
            using var context = CreateContext();
            var controller = new StudentsController(context);
            var student = new Student
            {
                LastName = "NewStudent",
                FirstMidName = "Test",
                EnrollmentDate = new DateTime(1000, 1, 1)
            };

            var result = controller.Create(student) as ViewResult;

            Assert.NotNull(result);
            Assert.False(controller.ModelState.IsValid);
        }

        [Fact]
        public void Edit_Get_ValidId_ReturnsViewWithStudent()
        {
            using var context = CreateContext();
            var controller = new StudentsController(context);

            var result = controller.Edit(1) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Student>(result.Model);
            Assert.Equal("Alexander", model.LastName);
        }

        [Fact]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            using var context = CreateContext();
            var controller = new StudentsController(context);

            var result = controller.Edit(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void Edit_Get_NotFoundId_ReturnsNotFound()
        {
            using var context = CreateContext();
            var controller = new StudentsController(context);

            var result = controller.Edit(999) as NotFoundResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Edit_Post_ValidStudent_RedirectsToIndex()
        {
            using var context = CreateContext();
            var controller = new StudentsController(context);
            var student = context.Students.Find(1);
            context.Entry(student).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var updatedStudent = new Student
            {
                ID = 1,
                LastName = "UpdatedName",
                FirstMidName = "Carson",
                EnrollmentDate = new DateTime(2020, 9, 1)
            };

            var result = controller.Edit(updatedStudent) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Edit_Post_InvalidEnrollmentDate_ReturnsViewWithError()
        {
            using var context = CreateContext();
            var controller = new StudentsController(context);
            var student = new Student
            {
                ID = 1,
                LastName = "Test",
                FirstMidName = "Student",
                EnrollmentDate = default
            };

            var result = controller.Edit(student) as ViewResult;

            Assert.NotNull(result);
            Assert.False(controller.ModelState.IsValid);
        }

        [Fact]
        public void Delete_Get_ValidId_ReturnsViewWithStudent()
        {
            using var context = CreateContext();
            var controller = new StudentsController(context);

            var result = controller.Delete(1) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Student>(result.Model);
            Assert.Equal("Alexander", model.LastName);
        }

        [Fact]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            using var context = CreateContext();
            var controller = new StudentsController(context);

            var result = controller.Delete(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void Delete_Get_NotFoundId_ReturnsNotFound()
        {
            using var context = CreateContext();
            var controller = new StudentsController(context);

            var result = controller.Delete(999) as NotFoundResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void DeleteConfirmed_ValidId_RemovesStudentAndRedirects()
        {
            using var context = CreateContext();
            var controller = new StudentsController(context);

            var result = controller.DeleteConfirmed(1) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Equal(2, context.Students.Count());
        }
    }
}

