using System;
using System.Linq;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Hosting;
using Microsoft.Extensions.Logging;
using Moq;
using Xunit;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;

namespace ContosoUniversity.Tests.Controllers
{
    public class CoursesControllerTests
    {
        private readonly Mock<IWebHostEnvironment> _mockEnv;
        private readonly Mock<ILogger<CoursesController>> _mockLogger;

        public CoursesControllerTests()
        {
            _mockEnv = new Mock<IWebHostEnvironment>();
            _mockEnv.Setup(e => e.WebRootPath).Returns("/tmp/wwwroot");
            _mockEnv.Setup(e => e.ContentRootPath).Returns("/tmp");
            _mockLogger = new Mock<ILogger<CoursesController>>();
        }

        private SchoolContext CreateContext() => TestDbContextFactory.CreateWithCoursesAndDepartments();

        [Fact]
        public void Index_ReturnsViewWithAllCourses()
        {
            using var context = CreateContext();
            var controller = new CoursesController(context, _mockEnv.Object, _mockLogger.Object);

            var result = controller.Index() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<System.Collections.Generic.List<Course>>(result.Model);
            Assert.Equal(3, model.Count);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithCourse()
        {
            using var context = CreateContext();
            var controller = new CoursesController(context, _mockEnv.Object, _mockLogger.Object);

            var result = controller.Details(1050) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Course>(result.Model);
            Assert.Equal("Chemistry", model.Title);
        }

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            using var context = CreateContext();
            var controller = new CoursesController(context, _mockEnv.Object, _mockLogger.Object);

            var result = controller.Details(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void Create_Get_ReturnsViewWithDepartmentSelectList()
        {
            using var context = CreateContext();
            var controller = new CoursesController(context, _mockEnv.Object, _mockLogger.Object);

            var result = controller.Create() as ViewResult;

            Assert.NotNull(result);
            Assert.NotNull(controller.ViewBag.DepartmentID);
        }

        [Fact]
        public void Create_Post_ValidCourse_RedirectsToIndex()
        {
            using var context = CreateContext();
            var controller = new CoursesController(context, _mockEnv.Object, _mockLogger.Object);
            var course = new Course
            {
                CourseID = 9999,
                Title = "New Course",
                Credits = 3,
                DepartmentID = 1
            };

            var result = controller.Create(course, null) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Equal(4, context.Courses.Count());
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            using var context = CreateContext();
            var controller = new CoursesController(context, _mockEnv.Object, _mockLogger.Object);
            controller.ModelState.AddModelError("Title", "Required");
            var course = new Course { CourseID = 9999, DepartmentID = 1 };

            var result = controller.Create(course, null) as ViewResult;

            Assert.NotNull(result);
            Assert.NotNull(controller.ViewBag.DepartmentID);
        }

        [Fact]
        public void Edit_Get_ValidId_ReturnsViewWithCourse()
        {
