using ContosoUniversity.Data;
using ContosoUniversity.Models;

namespace ContosoUniversity.Tests.Controllers
{
    public class DepartmentsControllerTests
    {
        private SchoolContext CreateContext() => TestDbContextFactory.CreateWithCoursesAndDepartments();

        [Fact]
        public void Index_ReturnsViewWithAllDepartments()
        {
            using var context = CreateContext();
            var controller = new DepartmentsController(context);

            var result = controller.Index() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<System.Collections.Generic.List<Department>>(result.Model);
            Assert.Single(model);
            Assert.Equal("Engineering", model[0].Name);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithDepartment()
        {
            using var context = CreateContext();
            var controller = new DepartmentsController(context);

            var result = controller.Details(1) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Department>(result.Model);
            Assert.Equal("Engineering", model.Name);
        }

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            using var context = CreateContext();
            var controller = new DepartmentsController(context);

            var result = controller.Details(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void Details_NotFoundId_ReturnsNotFound()
        {
            using var context = CreateContext();
            var controller = new DepartmentsController(context);

            var result = controller.Details(999) as NotFoundResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Create_Get_ReturnsViewWithInstructorSelectList()
        {
            using var context = CreateContext();
            var controller = new DepartmentsController(context);

            var result = controller.Create() as ViewResult;

            Assert.NotNull(result);
            Assert.NotNull(controller.ViewBag.InstructorID);
        }

        [Fact]
        public void Create_Post_ValidDepartment_RedirectsToIndex()
        {
            using var context = CreateContext();
            var controller = new DepartmentsController(context);
            var department = new Department
            {
                Name = "Science",
                Budget = 200000m,
                StartDate = new DateTime(2020, 1, 1),
                InstructorID = 1
            };

            var result = controller.Create(department) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Equal(2, context.Departments.Count());
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            using var context = CreateContext();
            var controller = new DepartmentsController(context);
            controller.ModelState.AddModelError("Name", "Required");
            var department = new Department();

            var result = controller.Create(department) as ViewResult;

            Assert.NotNull(result);
            Assert.NotNull(controller.ViewBag.InstructorID);
        }

        [Fact]
        public void Edit_Get_ValidId_ReturnsViewWithDepartment()
        {
            using var context = CreateContext();
