            var result = controller.Edit(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void Edit_Get_NotFoundId_ReturnsNotFound()
        {
            using var context = CreateContext();
            var controller = new DepartmentsController(context);

            var result = controller.Edit(999) as NotFoundResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Edit_Post_ValidDepartment_RedirectsToIndex()
        {
            using var context = CreateContext();
            var controller = new DepartmentsController(context);

            // Detach the tracked entity
            var existing = context.Departments.Find(1);
            context.Entry(existing).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var department = new Department
            {
                DepartmentID = 1,
                Name = "Updated Engineering",
                Budget = 400000m,
                StartDate = new DateTime(2007, 9, 1),
                InstructorID = 1
            };

            var result = controller.Edit(department) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Edit_Post_InvalidModelState_ReturnsView()
        {
            using var context = CreateContext();
            var controller = new DepartmentsController(context);
            controller.ModelState.AddModelError("Name", "Required");
            var department = new Department { DepartmentID = 1 };

            var result = controller.Edit(department) as ViewResult;

            Assert.NotNull(result);
            Assert.NotNull(controller.ViewBag.InstructorID);
        }

        [Fact]
        public void Delete_Get_ValidId_ReturnsViewWithDepartment()
        {
            using var context = CreateContext();
            var controller = new DepartmentsController(context);

            var result = controller.Delete(1) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Department>(result.Model);
            Assert.Equal("Engineering", model.Name);
        }

        [Fact]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            using var context = CreateContext();
            var controller = new DepartmentsController(context);

            var result = controller.Delete(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void Delete_Get_NotFoundId_ReturnsNotFound()
        {
            using var context = CreateContext();
            var controller = new DepartmentsController(context);

            var result = controller.Delete(999) as NotFoundResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void DeleteConfirmed_ValidId_RemovesDepartmentAndRedirects()
        {
            using var context = CreateContext();
            var controller = new DepartmentsController(context);

            var result = controller.DeleteConfirmed(1) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Equal(0, context.Departments.Count());
        }
    }
}

