using System;
using System.Collections.Generic;
using System.Linq;
using Microsoft.AspNetCore.Mvc;
using Xunit;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;

namespace ContosoUniversity.Tests.Controllers
{
    public class InstructorsControllerTests
    {
        private SchoolContext CreateContext() => TestDbContextFactory.CreateWithInstructors();

        [Fact]
        public void Index_NoParams_ReturnsViewWithAllInstructors()
        {
            using var context = CreateContext();
            var controller = new InstructorsController(context);

            var result = controller.Index(null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<InstructorIndexData>(result.Model);
            Assert.Equal(2, model.Instructors.Count());
        }

        [Fact]
        public void Index_WithInstructorId_PopulatesCourses()
        {
            using var context = CreateContext();
            var controller = new InstructorsController(context);

            var result = controller.Index(1, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<InstructorIndexData>(result.Model);
            Assert.NotNull(model.Courses);
            Assert.Single(model.Courses);
            Assert.Equal("Chemistry", model.Courses.First().Title);
        }

        [Fact]
        public void Index_WithCourseId_PopulatesEnrollments()
        {
            using var context = CreateContext();
            // Add an enrollment for course 1050
            var student = new Student { ID = 10, LastName = "Test", FirstMidName = "Student", EnrollmentDate = DateTime.Now };
            context.Students.Add(student);
            context.Enrollments.Add(new Enrollment { EnrollmentID = 1, CourseID = 1050, StudentID = 10, Grade = Grade.A });
            context.SaveChanges();

            var controller = new InstructorsController(context);

            var result = controller.Index(1, 1050) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<InstructorIndexData>(result.Model);
            Assert.NotNull(model.Enrollments);
            Assert.Single(model.Enrollments);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithInstructor()
        {
            using var context = CreateContext();
            var controller = new InstructorsController(context);

            var result = controller.Details(1) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Instructor>(result.Model);
            Assert.Equal("Fakhouri", model.LastName);
        }

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            using var context = CreateContext();
            var controller = new InstructorsController(context);

            var result = controller.Details(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void Details_NotFoundId_ReturnsNotFound()
        {
            using var context = CreateContext();
            var controller = new InstructorsController(context);

            var result = controller.Details(999) as NotFoundResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Create_Get_ReturnsViewWithInstructorAndCourseData()
        {
            using var context = CreateContext();
            var controller = new InstructorsController(context);

            var result = controller.Create() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Instructor>(result.Model);
            Assert.NotNull(model.CourseAssignments);
            Assert.NotNull(controller.ViewBag.Courses);
        }

        [Fact]
        public void Create_Post_ValidInstructor_RedirectsToIndex()
        {
            using var context = CreateContext();
            var controller = new InstructorsController(context);
            var instructor = new Instructor
            {
                LastName = "NewInstructor",
                FirstMidName = "Test",
                HireDate = new DateTime(2020, 1, 1),
                CourseAssignments = new List<CourseAssignment>()
            };

            var result = controller.Create(instructor, null) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Equal(3, context.Instructors.Count());
        }

        [Fact]
        public void Create_Post_WithSelectedCourses_AddsCourseAssignments()
        {
            using var context = CreateContext();
            var controller = new InstructorsController(context);
            var instructor = new Instructor
            {
                LastName = "CourseInstructor",
                FirstMidName = "With",
                HireDate = new DateTime(2020, 1, 1)
            };

            var result = controller.Create(instructor, new[] { "1050" }) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            var saved = context.Instructors
                .Where(i => i.LastName == "CourseInstructor")
                .Select(i => i.CourseAssignments)
                .First();
            Assert.Single(saved);
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            using var context = CreateContext();
            var controller = new InstructorsController(context);
            controller.ModelState.AddModelError("LastName", "Required");
            var instructor = new Instructor
            {
                CourseAssignments = new List<CourseAssignment>()
            };

            var result = controller.Create(instructor, null) as ViewResult;

            Assert.NotNull(result);
            Assert.NotNull(controller.ViewBag.Courses);
        }

        [Fact]
        public void Edit_Get_ValidId_ReturnsViewWithInstructor()
        {
            using var context = CreateContext();
            var controller = new InstructorsController(context);

            var result = controller.Edit((int?)1) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Instructor>(result.Model);
            Assert.Equal("Fakhouri", model.LastName);
            Assert.NotNull(controller.ViewBag.Courses);
        }

        [Fact]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            using var context = CreateContext();
            var controller = new InstructorsController(context);

            var result = controller.Edit((int?)null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void Delete_Get_ValidId_ReturnsViewWithInstructor()
        {
            using var context = CreateContext();
            var controller = new InstructorsController(context);

            var result = controller.Delete(1) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Instructor>(result.Model);
            Assert.Equal("Fakhouri", model.LastName);
        }

        [Fact]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            using var context = CreateContext();
            var controller = new InstructorsController(context);

