using System;
using Microsoft.AspNetCore.Mvc;
using Xunit;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;

namespace ContosoUniversity.Tests.Controllers
{
    public class NotificationsControllerTests
    {
        [Fact]
        public void GetNotifications_EmptyQueue_ReturnsSuccessWithEmptyList()
        {
            using var context = TestDbContextFactory.Create();
            var controller = new NotificationsController(context);

            // Drain any residual messages from the static queue
            var service = new NotificationService();
            while (service.ReceiveNotification() != null) { }

            var result = controller.GetNotifications();

            Assert.NotNull(result);
            var json = result.Value;
            Assert.NotNull(json);
            // Verify success response structure
            var successProp = json.GetType().GetProperty("success");
            Assert.NotNull(successProp);
            Assert.True((bool)successProp.GetValue(json));
        }

        [Fact]
        public void GetNotifications_WithMessages_ReturnsNotifications()
        {
            using var context = TestDbContextFactory.Create();
            var controller = new NotificationsController(context);

            // Drain queue, then add known messages
            var service = new NotificationService();
            while (service.ReceiveNotification() != null) { }

            service.SendNotification("Student", "1", "Test Student", EntityOperation.CREATE);
            service.SendNotification("Course", "2", "Test Course", EntityOperation.UPDATE);

            var result = controller.GetNotifications();

            Assert.NotNull(result);
            var json = result.Value;
            var countProp = json.GetType().GetProperty("count");
            Assert.NotNull(countProp);
            var count = (int)countProp.GetValue(json);
            Assert.True(count >= 2);
        }

        [Fact]
        public void MarkAsRead_ValidId_ReturnsSuccess()
        {
            using var context = TestDbContextFactory.Create();
            var controller = new NotificationsController(context);

            var result = controller.MarkAsRead(1);

            Assert.NotNull(result);
            var json = result.Value;
            var successProp = json.GetType().GetProperty("success");
            Assert.True((bool)successProp.GetValue(json));
        }

        [Fact]
        public void Index_ReturnsView()
        {
            using var context = TestDbContextFactory.Create();
            var controller = new NotificationsController(context);

            var result = controller.Index() as ViewResult;

            Assert.NotNull(result);
        }
    }
}

