using System.Linq;
using Xunit;
using ContosoUniversity.Data;
using ContosoUniversity.Models;

namespace ContosoUniversity.Tests.Data
{
    public class DbInitializerTests
    {
        [Fact]
        public void Initialize_EmptyDatabase_SeedsStudents()
        {
            using var context = TestDbContextFactory.Create();

            DbInitializer.Initialize(context);

            Assert.Equal(8, context.Students.Count());
        }

        [Fact]
        public void Initialize_EmptyDatabase_SeedsInstructors()
        {
            using var context = TestDbContextFactory.Create();

            DbInitializer.Initialize(context);

            Assert.Equal(5, context.Instructors.Count());
        }

        [Fact]
        public void Initialize_EmptyDatabase_SeedsDepartments()
        {
            using var context = TestDbContextFactory.Create();

            DbInitializer.Initialize(context);

            Assert.Equal(4, context.Departments.Count());
        }

        [Fact]
        public void Initialize_EmptyDatabase_SeedsCourses()
        {
            using var context = TestDbContextFactory.Create();

            DbInitializer.Initialize(context);

            Assert.Equal(7, context.Courses.Count());
        }

        [Fact]
        public void Initialize_EmptyDatabase_SeedsEnrollments()
        {
            using var context = TestDbContextFactory.Create();

            DbInitializer.Initialize(context);

            Assert.Equal(11, context.Enrollments.Count());
        }

        [Fact]
        public void Initialize_EmptyDatabase_SeedsOfficeAssignments()
        {
            using var context = TestDbContextFactory.Create();

            DbInitializer.Initialize(context);

            Assert.Equal(3, context.OfficeAssignments.Count());
        }

        [Fact]
        public void Initialize_EmptyDatabase_SeedsCourseAssignments()
        {
            using var context = TestDbContextFactory.Create();

            DbInitializer.Initialize(context);

            Assert.Equal(8, context.CourseAssignments.Count());
        }

        [Fact]
        public void Initialize_DatabaseAlreadySeeded_DoesNotDuplicate()
        {
            using var context = TestDbContextFactory.Create();

            // First initialization
            DbInitializer.Initialize(context);
            var initialStudentCount = context.Students.Count();

            // Second initialization should be a no-op
            DbInitializer.Initialize(context);

            Assert.Equal(initialStudentCount, context.Students.Count());
        }
    }
}

using System;
using System.Collections.Generic;
using Xunit;
using ContosoUniversity.Models;

namespace ContosoUniversity.Tests.Models
{
    public class ModelTests
    {
        [Fact]
        public void ErrorViewModel_ShowRequestId_True_WhenRequestIdIsSet()
        {
            var model = new ErrorViewModel { RequestId = "abc123" };
            Assert.True(model.ShowRequestId);
        }

        [Fact]
        public void ErrorViewModel_ShowRequestId_False_WhenRequestIdIsNull()
        {
            var model = new ErrorViewModel { RequestId = null };
            Assert.False(model.ShowRequestId);
        }

        [Fact]
        public void ErrorViewModel_ShowRequestId_False_WhenRequestIdIsEmpty()
        {
            var model = new ErrorViewModel { RequestId = "" };
            Assert.False(model.ShowRequestId);
        }

        [Fact]
        public void Student_Properties_SetAndGet()
        {
            var date = new DateTime(2023, 9, 1);
            var student = new Student
            {
                ID = 5,
                LastName = "Test",
                FirstMidName = "Student",
                EnrollmentDate = date,
                Enrollments = new List<Enrollment>()
            };

            Assert.Equal(5, student.ID);
            Assert.Equal("Test", student.LastName);
            Assert.Equal("Student", student.FirstMidName);
            Assert.Equal(date, student.EnrollmentDate);
            Assert.Empty(student.Enrollments);
            Assert.Equal("Test, Student", student.FullName);
        }

        [Fact]
        public void Instructor_Properties_SetAndGet()
        {
            var date = new DateTime(2010, 1, 1);
            var instructor = new Instructor
            {
                ID = 3,
                LastName = "Smith",
                FirstMidName = "Jane",
                HireDate = date,
                CourseAssignments = new List<CourseAssignment>(),
                OfficeAssignment = new OfficeAssignment { Location = "Room 1" }
            };

            Assert.Equal(3, instructor.ID);
            Assert.Equal("Smith", instructor.LastName);
            Assert.Equal("Jane", instructor.FirstMidName);
            Assert.Equal(date, instructor.HireDate);
            Assert.Empty(instructor.CourseAssignments);
            Assert.NotNull(instructor.OfficeAssignment);
            Assert.Equal("Smith, Jane", instructor.FullName);
        }

        [Fact]
        public void Course_Properties_SetAndGet()
        {
            var course = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = 1,
                TeachingMaterialImagePath = "/images/chem.png",
                Department = new Department { Name = "Science" },
                Enrollments = new List<Enrollment>(),
                CourseAssignments = new List<CourseAssignment>()
            };

            Assert.Equal(1050, course.CourseID);
            Assert.Equal("Chemistry", course.Title);
            Assert.Equal(3, course.Credits);
            Assert.Equal(1, course.DepartmentID);
            Assert.Equal("/images/chem.png", course.TeachingMaterialImagePath);
            Assert.NotNull(course.Department);
            Assert.Empty(course.Enrollments);
            Assert.Empty(course.CourseAssignments);
        }

        [Fact]
        public void Department_Properties_SetAndGet()
        {
            var dept = new Department
            {
                DepartmentID = 1,
                Name = "Engineering",
                Budget = 350000m,
                StartDate = new DateTime(2007, 9, 1),
                InstructorID = 5,
                RowVersion = new byte[] { 1, 2, 3, 4 },
                Administrator = new Instructor { LastName = "Admin", FirstMidName = "Test", HireDate = DateTime.Now },
                Courses = new List<Course>()
            };

            Assert.Equal(1, dept.DepartmentID);
            Assert.Equal("Engineering", dept.Name);
            Assert.Equal(350000m, dept.Budget);
            Assert.Equal(5, dept.InstructorID);
            Assert.NotNull(dept.RowVersion);
            Assert.NotNull(dept.Administrator);
            Assert.Empty(dept.Courses);
        }

        [Fact]
        public void Enrollment_Properties_SetAndGet()
        {
            var enrollment = new Enrollment
            {
                EnrollmentID = 1,
                CourseID = 100,
                StudentID = 200,
                Grade = Grade.A,
                Course = new Course { Title = "Math" },
                Student = new Student { LastName = "Doe", FirstMidName = "John", EnrollmentDate = DateTime.Now }
            };

            Assert.Equal(1, enrollment.EnrollmentID);
            Assert.Equal(100, enrollment.CourseID);
            Assert.Equal(200, enrollment.StudentID);
            Assert.Equal(Grade.A, enrollment.Grade);
            Assert.NotNull(enrollment.Course);
            Assert.NotNull(enrollment.Student);
        }

        [Fact]
        public void Enrollment_Grade_CanBeNull()
        {
            var enrollment = new Enrollment
            {
                EnrollmentID = 1,
                CourseID = 100,
                StudentID = 200,
                Grade = null
            };

            Assert.Null(enrollment.Grade);
        }

        [Fact]
        public void CourseAssignment_Properties_SetAndGet()
        {
            var ca = new CourseAssignment
            {
                InstructorID = 1,
                CourseID = 2,
                Instructor = new Instructor { LastName = "X", FirstMidName = "Y", HireDate = DateTime.Now },
                Course = new Course { Title = "Z" }
            };

            Assert.Equal(1, ca.InstructorID);
            Assert.Equal(2, ca.CourseID);
            Assert.NotNull(ca.Instructor);
            Assert.NotNull(ca.Course);
        }

        [Fact]
        public void OfficeAssignment_Properties_SetAndGet()
        {
            var oa = new OfficeAssignment
            {
                InstructorID = 1,
                Location = "Thompson 304",
                Instructor = new Instructor { LastName = "I", FirstMidName = "T", HireDate = DateTime.Now }
            };

            Assert.Equal(1, oa.InstructorID);
            Assert.Equal("Thompson 304", oa.Location);
            Assert.NotNull(oa.Instructor);
        }

        [Fact]
        public void Notification_Properties_SetAndGet()
        {
            var now = DateTime.Now;
            var notification = new Notification
            {
