        public void OfficeAssignment_Properties_SetAndGet()
        {
            var oa = new OfficeAssignment
            {
                InstructorID = 1,
                Location = "Thompson 304",
                Instructor = new Instructor { LastName = "I", FirstMidName = "T", HireDate = DateTime.Now }
            };

            Assert.Equal(1, oa.InstructorID);
            Assert.Equal("Thompson 304", oa.Location);
            Assert.NotNull(oa.Instructor);
        }

        [Fact]
        public void Notification_Properties_SetAndGet()
        {
            var now = DateTime.Now;
            var notification = new Notification
            {
                Id = 1,
                EntityType = "Student",
                EntityId = "42",
                Operation = "CREATE",
                Message = "New student",
                CreatedAt = now,
                CreatedBy = "Admin",
                IsRead = true,
                ReadAt = now.AddMinutes(5)
            };

            Assert.Equal(1, notification.Id);
            Assert.Equal("Student", notification.EntityType);
            Assert.Equal("42", notification.EntityId);
            Assert.Equal("CREATE", notification.Operation);
            Assert.Equal("New student", notification.Message);
            Assert.Equal(now, notification.CreatedAt);
            Assert.Equal("Admin", notification.CreatedBy);
