        [InlineData(Grade.C)]
        [InlineData(Grade.D)]
        [InlineData(Grade.F)]
        public void Grade_Enum_HasExpectedValues(Grade grade)
        {
            Assert.True(Enum.IsDefined(typeof(Grade), grade));
        }
    }
