using System;
using System.IO;
using System.Linq;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.Extensions.Logging;
using Moq;
using Xunit;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;

namespace ContosoUniversity.Tests.Controllers
{
    /// <summary>
    /// Additional tests for file upload and edge cases in CoursesController.
    /// </summary>
    public class CoursesControllerFileUploadTests : IDisposable
    {
        private readonly string _tempDir;
        private readonly Mock<IWebHostEnvironment> _mockEnv;
        private readonly Mock<ILogger<CoursesController>> _mockLogger;

        public CoursesControllerFileUploadTests()
        {
            _tempDir = Path.Combine(Path.GetTempPath(), "CoursesTest_" + Guid.NewGuid().ToString("N"));
            Directory.CreateDirectory(_tempDir);
            _mockEnv = new Mock<IWebHostEnvironment>();
            _mockEnv.Setup(e => e.WebRootPath).Returns(_tempDir);
            _mockEnv.Setup(e => e.ContentRootPath).Returns(_tempDir);
            _mockLogger = new Mock<ILogger<CoursesController>>();
        }

        public void Dispose()
        {
            if (Directory.Exists(_tempDir))
                Directory.Delete(_tempDir, true);
        }

        private SchoolContext CreateContext() => TestDbContextFactory.CreateWithCoursesAndDepartments();

        [Fact]
        public void Create_Post_ValidImage_SavesFileAndRedirects()
        {
            using var context = CreateContext();
            var controller = new CoursesController(context, _mockEnv.Object, _mockLogger.Object);
            var course = new Course { CourseID = 7777, Title = "Art", Credits = 2, DepartmentID = 1 };

            var content = new byte[] { 0x89, 0x50, 0x4E, 0x47 }; // Minimal PNG-like header
            var mockFile = new Mock<IFormFile>();
            mockFile.Setup(f => f.FileName).Returns("test.png");
            mockFile.Setup(f => f.Length).Returns(content.Length);
            mockFile.Setup(f => f.CopyTo(It.IsAny<Stream>()))
                .Callback<Stream>(s => s.Write(content, 0, content.Length));

            var result = controller.Create(course, mockFile.Object) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.NotNull(context.Courses.Find(7777).TeachingMaterialImagePath);
            Assert.StartsWith("/Uploads/TeachingMaterials/", context.Courses.Find(7777).TeachingMaterialImagePath);
        }

        [Fact]
        public void Edit_Post_ValidImage_SavesFileAndRedirects()
        {
            using var context = CreateContext();
            var controller = new CoursesController(context, _mockEnv.Object, _mockLogger.Object);

            // Detach tracked entity
            var existing = context.Courses.Find(1050);
            context.Entry(existing).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var course = new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = 1 };

            var content = new byte[] { 0xFF, 0xD8, 0xFF }; // JPEG header
            var mockFile = new Mock<IFormFile>();
            mockFile.Setup(f => f.FileName).Returns("photo.jpg");
            mockFile.Setup(f => f.Length).Returns(content.Length);
            mockFile.Setup(f => f.CopyTo(It.IsAny<Stream>()))
                .Callback<Stream>(s => s.Write(content, 0, content.Length));

            var result = controller.Edit(course, mockFile.Object) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Edit_Post_WithExistingImage_DeletesOldFile()
        {
            using var context = CreateContext();

            // Create an existing file to simulate old image
            var uploadsPath = Path.Combine(_tempDir, "Uploads", "TeachingMaterials");
            Directory.CreateDirectory(uploadsPath);
            var oldFilePath = Path.Combine(uploadsPath, "old_image.png");
            File.WriteAllText(oldFilePath, "old");

            // Update the course in context to have an existing image path
            var existing = context.Courses.Find(1050);
            existing.TeachingMaterialImagePath = "/Uploads/TeachingMaterials/old_image.png";
            context.SaveChanges();
            context.Entry(existing).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var controller = new CoursesController(context, _mockEnv.Object, _mockLogger.Object);
            var course = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = 1,
                TeachingMaterialImagePath = "/Uploads/TeachingMaterials/old_image.png"
            };

            var content = new byte[] { 0xFF, 0xD8 };
            var mockFile = new Mock<IFormFile>();
            mockFile.Setup(f => f.FileName).Returns("new.jpg");
            mockFile.Setup(f => f.Length).Returns(content.Length);
            mockFile.Setup(f => f.CopyTo(It.IsAny<Stream>()))
                .Callback<Stream>(s => s.Write(content, 0, content.Length));

            var result = controller.Edit(course, mockFile.Object) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.False(File.Exists(oldFilePath));
        }

        [Fact]
        public void DeleteConfirmed_WithImage_DeletesImageFile()
        {
            using var context = CreateContext();

            // Create the image file
            var uploadsPath = Path.Combine(_tempDir, "Uploads", "TeachingMaterials");
            Directory.CreateDirectory(uploadsPath);
            var imagePath = Path.Combine(uploadsPath, "course_1050.png");
            File.WriteAllText(imagePath, "image");

            var course = context.Courses.Find(1050);
            course.TeachingMaterialImagePath = "/Uploads/TeachingMaterials/course_1050.png";
            context.SaveChanges();

            var controller = new CoursesController(context, _mockEnv.Object, _mockLogger.Object);

            var result = controller.DeleteConfirmed(1050) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.False(File.Exists(imagePath));
        }

        [Fact]
        public void Create_Post_FileUploadThrows_ReturnsViewWithError()
        {
            using var context = CreateContext();
            // Use a path that will cause an error (null WebRootPath with bad path)
            var badEnv = new Mock<IWebHostEnvironment>();
            badEnv.Setup(e => e.WebRootPath).Returns((string)null);
            badEnv.Setup(e => e.ContentRootPath).Returns("/nonexistent/path/that/cannot/be/created/" + new string('x', 300));

            var controller = new CoursesController(context, badEnv.Object, _mockLogger.Object);
            var course = new Course { CourseID = 5555, Title = "Test", Credits = 1, DepartmentID = 1 };

            var mockFile = new Mock<IFormFile>();
            mockFile.Setup(f => f.FileName).Returns("image.png");
            mockFile.Setup(f => f.Length).Returns(1024);
            mockFile.Setup(f => f.CopyTo(It.IsAny<Stream>())).Throws(new IOException("Disk full"));

            var result = controller.Create(course, mockFile.Object) as ViewResult;

            Assert.NotNull(result);
            Assert.True(controller.ModelState.ContainsKey("teachingMaterialImage"));
        }
    }
}

